(1, 'AI 与大模型技术前沿讲座', 'academic', '本次讲座邀请业界专家，介绍大模型在软件工程、教育等领域的最新应用与发展趋势，适合对 AI 感兴趣的同学参加。', '2026-07-15 14:00:00.000', '2026-07-15 16:00:00.000', '软件大楼 A101', 'T001', '软件学院', 'https://picsum.photos/seed/ai-lecture/800/400', 120, 85, 42, 520, 0, 38.15, 'published', '["AI", "编程"]', 'AI2026'),
(2, '校园羽毛球友谊赛', 'sports', '面向全校师生的羽毛球双打友谊赛，按学院分组，优胜队伍将获得精美奖品。请提前热身，穿运动服参赛。', '2026-07-20 09:00:00.000', '2026-07-20 12:00:00.000', '体育馆羽毛球场', '524030910002', '计算机学院', 'https://picsum.photos/seed/badminton/800/400', 64, 43, 28, 310, 0, 28.4, 'published', '["羽毛球", "体育运动"]', 'BD2026'),
(3, '摄影社户外采风活动', 'club', '摄影社组织校园及周边人文采风，专业学长带队讲解构图与后期技巧，欢迎零基础同学加入。', '2026-07-18 08:00:00.000', '2026-07-18 17:00:00.000', '图书馆前广场集合', '524030910001', '软件学院', 'https://picsum.photos/seed/photo-club/800/400', 30, 22, 35, 280, 0, 32.1, 'published', '["摄影", "艺术"]', 'PH2026'),
(4, '程序设计竞赛训练营', 'innovation', '为期一周的算法与数据结构强化训练，涵盖动态规划、图论等高频考点，为 ACM/ICPC 及各类编程竞赛做准备。', '2026-07-22 19:00:00.000', '2026-07-29 21:00:00.000', '计算机楼 302 实验室', 'T001', '计算机学院', 'https://picsum.photos/seed/coding/800/400', 50, 38, 56, 640, 0, 45.2, 'published', '["编程", "AI"]', 'CP2026'),
(5, '校园志愿者招募 — 社区服务日', 'volunteer', '组织同学前往周边社区开展助老、环境清洁等志愿服务，可计入志愿服务时长，欢迎热心公益的同学报名。', '2026-07-25 08:30:00.000', '2026-07-25 16:00:00.000', '校门口集合', '524030910001', '软件学院', 'https://picsum.photos/seed/volunteer/800/400', 40, 31, 19, 210, 31, 24.8, 'ended', '["志愿服务"]', 'VL2026'),
(6, '校园音乐节 — 夏日之声', 'arts', '各社团及个人歌手同台演出，涵盖流行、摇滚、民谣等多种风格，现场还有互动抽奖环节。', '2026-06-28 18:30:00.000', '2026-06-28 21:30:00.000', '中心广场', '524030910002', '信息学院', 'https://picsum.photos/seed/music/800/400', 500, 412, 198, 3200, 380, 210.5, 'ended', '["音乐", "文艺"]', 'MU2026'),
(7, '三人篮球校园联赛', 'sports', '3v3 街头篮球赛，开赛前有热身教学，适合各类水平球员。强对抗、快节奏，欢迎热爱篮球的同学组队参赛。', '2026-07-21 15:00:00.000', '2026-07-21 19:00:00.000', '室外篮球场', '524030910002', '计算机学院', 'https://picsum.photos/seed/basketball/800/400', 48, 36, 22, 290, 0, 26.0, 'published', '["篮球", "体育运动"]', 'BK2026'),
(8, '量子计算与量子物理入门讲座', 'academic', '从量子叠加与纠缠讲起，介绍量子比特、量子门与近期量子计算实验进展，偏重物理与信息科学交叉，需具备一定数理基础。', '2026-07-16 19:00:00.000', '2026-07-16 21:00:00.000', '理科楼报告厅', 'T001', '信息学院', 'https://picsum.photos/seed/quantum/800/400', 100, 47, 18, 260, 0, 22.3, 'published', '["物理", "学术"]', 'QU2026'),
(9, '烘焙社 — 周末手工饼干工作坊', 'club', '亲手完成一盒黄油曲奇，学习称量、搅拌与烤箱温度控制。材料现场提供，适合想轻松解压、体验动手乐趣的同学。', '2026-07-19 14:00:00.000', '2026-07-19 17:00:00.000', '学生活动中心厨房', '524030910001', '软件学院', 'https://picsum.photos/seed/baking/800/400', 20, 18, 27, 190, 0, 21.6, 'published', '["烘焙", "休闲"]', 'BA2026'),
(10, '校际辩论邀请赛选拔', 'academic', '围绕公共议题进行立论、质询与结辩训练，最终选拔代表队参加校际辩论赛。锻炼逻辑表达与临场应变。', '2026-07-17 18:30:00.000', '2026-07-17 21:00:00.000', '教学楼 B203', 'T001', '软件学院', 'https://picsum.photos/seed/debate/800/400', 40, 25, 15, 150, 0, 16.8, 'published', '["辩论", "表达"]', 'DB2026'),
(11, '大学生创业路演夜', 'innovation', '创业团队 8 分钟路演 + 导师点评，主题涵盖校园服务、教具硬件与社交媒体产品。寻找合伙人或早期用户的同学欢迎观摩。', '2026-07-23 18:00:00.000', '2026-07-23 21:00:00.000', '创业孵化中心', 'T001', '计算机学院', 'https://picsum.photos/seed/startup/800/400', 80, 52, 33, 410, 0, 34.5, 'published', '["创业", "创新"]', 'ST2026'),
(12, '心理健康工作坊 — 压力与放松', 'club', '循证放松练习、正念呼吸与情绪日记分享，帮助缓解备考与实习压力。小班引导，注重隐私与安全感。', '2026-07-24 16:00:00.000', '2026-07-24 18:00:00.000', '心理中心团体室', '524030910001', '软件学院', 'https://picsum.photos/seed/mindfulness/800/400', 25, 19, 41, 330, 0, 29.7, 'published', '["心理", "放松"]', 'MH2026'),
(13, '书法社团钢笔字入门课', 'arts', '临摹楷书基本笔画与结构，适合想把笔记写工整、培养静心习惯的同学。笔墨纸自备或现场借阅。', '2026-07-18 19:00:00.000', '2026-07-18 21:00:00.000', '文科楼书画室', '524030910002', '信息学院', 'https://picsum.photos/seed/calligraphy/800/400', 28, 14, 12, 120, 0, 11.2, 'published', '["书法", "文艺"]', 'CL2026'),
(14, '机器人兴趣小组调试日', 'innovation', '轮式小车传感器校准与路径跟踪 demo，组队完成迷宫闯关。欢迎电子、机械与编程方向混合组队。', '2026-07-26 09:00:00.000', '2026-07-26 17:00:00.000', '工训中心 B区', 'T001', '计算机学院', 'https://picsum.photos/seed/robot/800/400', 36, 29, 24, 270, 0, 23.9, 'published', '["机器人", "编程"]', 'RB2026'),
(15, '英语角 — Movie Night 观影畅谈', 'club', '英文电影片段赏析后分组讨论剧情与角色，轻松练习口语。无需口语达人，欢迎想找语伴的同学。', '2026-07-19 19:30:00.000', '2026-07-19 21:30:00.000', '国际交流中心', '524030910001', '软件学院', 'https://picsum.photos/seed/english/800/400', 35, 21, 16, 180, 0, 15.4, 'published', '["英语", "交流"]', 'EN2026'),
(16, '校园趣味马拉松 5 公里', 'sports', '绕校园一圈的欢乐跑，补给站提供能量胶与饮水，完赛有纪念奖牌。重在参与，不设奖金排名。', '2026-07-27 07:00:00.000', '2026-07-27 10:00:00.000', '体育馆南门起跑', '524030910002', '信息学院', 'https://picsum.photos/seed/run/800/400', 200, 96, 55, 780, 0, 58.6, 'published', '["跑步", "体育运动"]', 'RN2026'),
(17, '桌游社周末解压局', 'club', '狼人杀、阿瓦隆与合作类桌游多桌并行，零食饮料自备。周末晚上来换脑子、认识新朋友。', '2026-07-18 20:00:00.000', '2026-07-19 00:00:00.000', '学生宿舍区活动室', '524030910002', '计算机学院', 'https://picsum.photos/seed/boardgame/800/400', 40, 33, 29, 240, 0, 27.1, 'published', '["桌游", "休闲"]', 'BG2026'),
(18, '有机化学实验室开放日', 'academic', '展示基本有机合成与光谱表征过程，参观安全规范与废液处理。对化学、材料感兴趣的同学优先报名。', '2026-07-22 13:30:00.000', '2026-07-22 16:30:00.000', '化学楼 2 号实验室', 'T001', '信息学院', 'https://picsum.photos/seed/chem/800/400', 30, 17, 9, 95, 0, 10.5, 'published', '["化学", "实验"]', 'CH2026'),
(19, '心理学社户外实践', 'club', '轻松的社团氛围，围绕心理学社兴趣主题展开交流与动手实践。适合想认识同好、丰富课余生活的同学。 报名截止前可随时取消；请关注活动群通知。', '2026-07-02 18:00:00.000', '2026-07-02 20:30:00.000', '文科楼书画室', '523030920033', '电子学院', 'https://picsum.photos/seed/act19/800/400', 200, 126, 68, 1431, 114, 112.68, 'ended', '["电影", "休闲", "机器人"]', 'CL0019'),
(20, '暑期社会实践 — 儿童课业辅导（第7期）', 'volunteer', '面向热心公益的师生招募，完成本次儿童课业辅导任务后可获得志愿证明与纪念品。欢迎首次参加志愿活动的同学。 报名截止前可随时取消；请关注活动群通知。', '2026-05-07 15:30:00.000', '2026-05-07 18:30:00.000', '化学楼 2 号实验室', '522030920160', '机械学院', 'https://picsum.photos/seed/act20/800/400', 300, 246, 140, 1125, 130, 179.1, 'ended', '["公益", "阅读", "旅行"]', 'VO0020'),
