(1490, '相声小品工作坊 · 入门体验（第2期）', 'arts', '以相声小品为主题的文艺活动，涵盖展示、教学与合影环节。欢迎各院系文艺爱好者报名演出或当观众。 报名截止前可随时取消；请关注活动群通知。', '2026-06-30 18:00:00.000', '2026-06-30 20:00:00.000', '媒体中心演播室', '525030920003', '信息学院', 'https://picsum.photos/seed/act1490/800/400', 48, 22, 21, 172, 19, 23.95, 'ended', '["音乐", "舞蹈"]', 'AR1490'),
(1491, '外国语学院 · 相声小品大师课观摩', 'arts', '沉浸式相声小品体验，现场有指导与作品点评。结束后优秀作品将有机会在校园媒体平台展示。 报名截止前可随时取消；请关注活动群通知。', '2026-08-17 16:00:00.000', '2026-08-17 20:00:00.000', '北区报告厅', 'T015', '计算机学院', 'https://picsum.photos/seed/act1491/800/400', 48, 16, 25, 273, 5, 20.76, 'published', '["舞蹈", "文艺"]', 'AR1491'),
(1492, '足球入门体验课', 'sports', '面向全校师生的足球活动，按水平分组，重在参与与交流。请穿着合适运动装备，提前热身；现场提供基础器材，优胜者可获纪念奖品。 请携带校园卡以便签到核验。', '2026-07-04 20:30:00.000', '2026-07-05 04:30:00.000', '创新工场', '524030920038', '软件学院', 'https://picsum.photos/seed/act1492/800/400', 64, 46, 25, 432, 26, 36.65, 'ended', '["篮球", "体育运动"]', 'SP1492'),
(1493, '桌游社技能分享会', 'club', '轻松的社团氛围，围绕桌游社兴趣主题展开交流与动手实践。适合想认识同好、丰富课余生活的同学。 现场可能拍照记录用于宣传，如有不便请提前告知组织者。', '2026-09-07 15:30:00.000', '2026-09-07 17:00:00.000', '网球场', '523030920029', '生命学院', 'https://picsum.photos/seed/act1493/800/400', 20, 2, 11, 92, 0, 8.86, 'draft', '["电竞", "休闲", "话剧"]', 'CL1493'),
(1494, '计算机学院 · 数值分析与科学计算科研方法分享', 'academic', '本次活动邀请校内外学者与业界嘉宾，围绕数值分析与科学计算展开系统讲解，结合最新论文与落地案例，适合相关专业及跨院系同学参与。活动含提问互动环节，欢迎提前准备问题。 活动开始前 15 分钟开放签到，迟到超过 30 分钟可能无法入场。', '2026-05-20 18:30:00.000', '2026-05-20 21:00:00.000', '心理中心团体室', 'T040', '计算机学院', 'https://picsum.photos/seed/act1494/800/400', 40, 11, 17, 247, 10, 16.21, 'ended', '["学术", "阅读", "心理"]', 'AC1494'),
(1495, '信息检索与推荐前沿讲座（第3期）', 'academic', '面向本科生与研究生，介绍信息检索与推荐的基本概念、常用方法与近期研究进展。现场提供讲义提纲，建议自备笔记本。名额有限，请按时签到入场。', '2026-06-12 19:00:00.000', '2026-06-12 21:00:00.000', '理科楼报告厅', '525030920143', '数学学院', 'https://picsum.photos/seed/act1495/800/400', 20, 7, 17, 77, 4, 12.26, 'ended', '["编程", "AI"]', 'AC1495'),
(1496, '人文学院 · 教育科技工具创新工作坊', 'innovation', '聚焦教育科技工具的创意落地，从问题定义到原型演示。适合想参加竞赛、申请项目或寻找合伙人的同学。 报名截止前可随时取消；请关注活动群通知。', '2026-06-06 19:00:00.000', '2026-06-06 21:30:00.000', '理科楼报告厅', 'T010', '人文学院', 'https://picsum.photos/seed/act1496/800/400', 36, 10, 5, 229, 7, 11.18, 'ended', '["机器人", "编程"]', 'IN1496'),
(1497, '周末书法公开课', 'arts', '专业老师与社团骨干带领同学体验书法基础技法，提供部分道具与材料。适合想培养审美与表达能力的同学。 报名截止前可随时取消；请关注活动群通知。', '2026-08-30 15:00:00.000', '2026-08-30 19:00:00.000', '体育馆羽毛球场', '525030920115', '电子学院', 'https://picsum.photos/seed/act1497/800/400', 48, 37, 38, 605, 10, 36.12, 'published', '["话剧", "表达", "创业"]', 'AR1497'),
(1498, '天文社学期招新宣讲（第3期）', 'club', '本场活动由天文社骨干学长学姐带队，讲解基础技巧并组织小组实践。结束后可自愿提交作品参加社内评选。 建议提前查阅相关资料，便于互动提问。', '2026-08-08 15:00:00.000', '2026-08-08 17:00:00.000', '西区咖啡厅', '525030920127', '外国语学院', 'https://picsum.photos/seed/act1498/800/400', 20, 12, 22, 114, 4, 16.69, 'published', '["摄影", "艺术", "编程"]', 'CL1498'),
(1499, '辩论社主题活动日', 'club', '辩论社定期活动，包含短分享、自由练习与合影留念。请提前在群内确认地点变更与天气预案。 请携带校园卡以便签到核验。', '2026-04-18 16:30:00.000', '2026-04-18 22:30:00.000', '软件大楼 B203', '525030920079', '电子学院', 'https://picsum.photos/seed/act1499/800/400', 100, 54, 17, 610, 35, 39.86, 'ended', '["心理", "放松"]', 'CL1499'),
(1500, '爱心接力：考试周自习室维护', 'volunteer', '与社区/校内部门合作开展考试周自习室维护，强调尊重服务对象与团队协作。活动前后有简短培训与复盘分享。 活动开始前 15 分钟开放签到，迟到超过 30 分钟可能无法入场。', '2026-05-20 16:00:00.000', '2026-05-20 19:00:00.000', '体育馆篮球馆', '522030920156', '机械学院', 'https://picsum.photos/seed/act1500/800/400', 64, 53, 27, 285, 47, 42.7, 'ended', '["志愿服务"]', 'VO1500');
